-- math: Place Value to Hundred Thousands
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Place Value to Hundred Thousands", "body": "Each digit in a number has a value based on its place: ones, tens, hundreds, thousands, and beyond. The same digit is worth more the farther left it sits."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the value of the digit 4 in 492,227? (Write just the number, e.g. 4000)\n\nThe answer is \"400000\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the value of the digit 9 in 961,930? (Write just the number, e.g. 4000)\n\nThe answer is \"900\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the value of the digit 4 in 442,259? (Write just the number, e.g. 4000)\n\nThe answer is \"400000\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the value of the digit 1 in 969,414? (Write just the number, e.g. 4000)\n\nThe answer is 10."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the value of the digit 5 in 251,156? (Write just the number, e.g. 4000)\n\nThe answer is 50000."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the value of the digit 4 in 383,403? (Write just the number, e.g. 4000)\n\nThe answer is 400."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Place Value to Hundred Thousands! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$place-value-to-hundred-thousands$tl$ and t.grade_level = 4);

-- math: Rounding Large Numbers
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Rounding Large Numbers", "body": "To round, look at the digit just to the right of the place you're rounding to. If it's 5 or more, round up; if it's less than 5, round down."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Round 715 to the nearest ten.\n\nThe answer is \"720\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Round 6,536 to the nearest hundred.\n\nThe answer is \"6500\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Round 7,622 to the nearest hundred.\n\nThe answer is \"7600\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Round 1,093 to the nearest ten.\n\nThe answer is 1090."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Round 1,219 to the nearest ten.\n\nThe answer is 1220."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Round 49,518 to the nearest thousand.\n\nThe answer is 50000."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Rounding Large Numbers! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$rounding-large-numbers$tl$ and t.grade_level = 4);

-- math: Multi-Digit Addition & Subtraction
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Multi-Digit Addition & Subtraction", "body": "Line up numbers by place value, then add or subtract one column at a time, regrouping (carrying or borrowing) when needed."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Add: 64,536 + 25,551 = ?\n\nThe answer is \"90087\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Subtract: 46,671 - 9,774 = ?\n\nThe answer is \"36897\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Add: 78,349 + 60,363 = ?\n\nThe answer is \"138712\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Add: 24,506 + 16,281 = ?\n\nThe answer is 40787."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Subtract: 84,781 - 27,804 = ?\n\nThe answer is 56977."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Add: 20,316 + 11,786 = ?\n\nThe answer is 32102."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Multi-Digit Addition & Subtraction! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$multi-digit-addition-and-subtraction$tl$ and t.grade_level = 4);

-- math: Multiply by a One-Digit Number
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Multiply by a One-Digit Number", "body": "Break the big number into place values, multiply each part by the one-digit number, then add the partial products together."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Multiply: 4 x 133 = ?\n\nThe answer is \"532\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Multiply: 9 x 496 = ?\n\nThe answer is \"4464\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Multiply: 8 x 906 = ?\n\nThe answer is \"7248\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Multiply: 4 x 375 = ?\n\nThe answer is 1500."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Multiply: 2 x 982 = ?\n\nThe answer is 1964."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Multiply: 5 x 505 = ?\n\nThe answer is 2525."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Multiply by a One-Digit Number! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
