update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Multiply Two Two-Digit Numbers", "body": "Split each number into tens and ones and multiply every part by every part (the area model), then add up all the partial products."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Multiply: 22 x 71 = ?\n\nThe answer is \"1562\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Multiply: 64 x 49 = ?\n\nThe answer is \"3136\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Multiply: 91 x 73 = ?\n\nThe answer is \"6643\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Multiply: 60 x 75 = ?\n\nThe answer is 4500."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Multiply: 56 x 66 = ?\n\nThe answer is 3696."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Multiply: 54 x 26 = ?\n\nThe answer is 1404."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Multiply Two Two-Digit Numbers! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
