  where s.slug = $tl$math$tl$ and t.slug = $tl$multiply-two-digit-numbers$tl$ and t.grade_level = 4);

-- math: Division with Remainders
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Division with Remainders", "body": "Divide to find how many equal groups you can make (the quotient). Whatever is left over and can't make a full group is the remainder."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the quotient (whole-number part) of 103 / 8?\n\nThe answer is \"12\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the remainder of 79 / 4?\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the quotient (whole-number part) of 357 / 8?\n\nThe answer is \"44\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the quotient (whole-number part) of 149 / 5?\n\nThe answer is 29."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the remainder of 386 / 6?\n\nThe answer is 2."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the quotient (whole-number part) of 357 / 8?\n\nThe answer is 44."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Division with Remainders! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$division-with-remainders$tl$ and t.grade_level = 4);

-- math: Factors & Multiples
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Factors & Multiples", "body": "A factor divides a number evenly with no remainder. A multiple is what you get when you skip-count by a number."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which number is a factor of 30?\n\nThe answer is \"15\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which number is a multiple of 4?\n\nThe answer is \"24\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which number is a factor of 12?\n\nThe answer is \"4\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is a multiple of 3?", "choices": [{"id": "a", "label": "22"}, {"id": "b", "label": "23"}, {"id": "c", "label": "24"}, {"id": "d", "label": "25"}], "answer": "c", "explanation": "Yes! The answer is \"24\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is a factor of 18?", "choices": [{"id": "a", "label": "7"}, {"id": "b", "label": "13"}, {"id": "c", "label": "14"}, {"id": "d", "label": "2"}], "answer": "d", "explanation": "Yes! The answer is \"2\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which number is a multiple of 9?", "choices": [{"id": "a", "label": "55"}, {"id": "b", "label": "56"}, {"id": "c", "label": "55"}, {"id": "d", "label": "54"}], "answer": "d", "explanation": "Yes! The answer is \"54\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Factors & Multiples! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$factors-and-multiples$tl$ and t.grade_level = 4);

-- math: Equivalent Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Equivalent Fractions", "body": "Two fractions are equivalent if they show the same amount. Multiply (or divide) the top and bottom by the same number to find one."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which fraction is equivalent to 2/5?\n\nThe answer is \"4/10\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which fraction is equivalent to 1/4?\n\nThe answer is \"3/12\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which fraction is equivalent to 1/3?\n\nThe answer is \"4/12\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is equivalent to 2/3?", "choices": [{"id": "a", "label": "9/12"}, {"id": "b", "label": "8/13"}, {"id": "c", "label": "3/4"}, {"id": "d", "label": "8/12"}], "answer": "d", "explanation": "Yes! The answer is \"8/12\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is equivalent to 1/3?", "choices": [{"id": "a", "label": "3/6"}, {"id": "b", "label": "2/6"}, {"id": "c", "label": "2/7"}, {"id": "d", "label": "2/4"}], "answer": "b", "explanation": "Yes! The answer is \"2/6\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is equivalent to 3/5?", "choices": [{"id": "a", "label": "7/10"}, {"id": "b", "label": "6/11"}, {"id": "c", "label": "4/6"}, {"id": "d", "label": "6/10"}], "answer": "d", "explanation": "Yes! The answer is \"6/10\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Equivalent Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
