-- math: Comparing Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Fractions", "body": "When two fractions have the same denominator, the one with the bigger numerator (top number) is greater."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which fraction is greater: 3/4 or 1/4?\n\nThe answer is \"3/4\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which fraction is greater: 1/6 or 3/6?\n\nThe answer is \"3/6\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which fraction is greater: 8/10 or 1/10?\n\nThe answer is \"8/10\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 2/6 or 4/6?", "choices": [{"id": "a", "label": "2/6"}, {"id": "b", "label": "4/6"}, {"id": "c", "label": "They are equal"}, {"id": "d", "label": "6/6"}], "answer": "b", "explanation": "Yes! The answer is \"4/6\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 3/8 or 5/8?", "choices": [{"id": "a", "label": "3/8"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "8/8"}, {"id": "d", "label": "5/8"}], "answer": "d", "explanation": "Yes! The answer is \"5/8\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 2/5 or 1/5?", "choices": [{"id": "a", "label": "1/5"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "3/5"}, {"id": "d", "label": "2/5"}], "answer": "d", "explanation": "Yes! The answer is \"2/5\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$comparing-fractions$tl$ and t.grade_level = 4);

-- math: Adding & Subtracting Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Adding & Subtracting Fractions", "body": "When denominators are the same, just add or subtract the numerators and keep the denominator the same."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Add the fractions: 4/6 + 1/6 = ?  (Write as a fraction like 5/6)\n\nThe answer is \"5/6\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Subtract: 2/5 - 1/5 = ?  (Write as a fraction like 2/5)\n\nThe answer is \"1/5\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Add the fractions: 2/6 + 3/6 = ?  (Write as a fraction like 5/6)\n\nThe answer is \"5/6\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Add the fractions: 7/10 + 1/10 = ?  (Write as a fraction like 5/10)\n\nThe answer is 8/10."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Subtract: 3/5 - 2/5 = ?  (Write as a fraction like 2/5)\n\nThe answer is 1/5."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Add the fractions: 2/8 + 4/8 = ?  (Write as a fraction like 5/8)\n\nThe answer is 6/8."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Adding & Subtracting Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$adding-fractions-like-denominators$tl$ and t.grade_level = 4);

-- science: Energy & Motion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Energy & Motion", "body": "Energy is the ability to do work or cause change. Moving things have kinetic energy; stored-up energy (like a stretched spring) is potential energy."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Energy that is moving, like a rolling ball, is called what?\n\nThe answer is \"kinetic energy\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A stretched rubber band ready to snap back is an example of what?\n\nThe answer is \"stored (potential) energy\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  When you rub your hands together quickly, the energy you feel is mostly:\n\nThe answer is \"heat (thermal) energy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A faster-moving object has MORE of which kind of energy?", "choices": [{"id": "a", "label": "less energy"}, {"id": "b", "label": "stored energy"}, {"id": "c", "label": "no energy"}, {"id": "d", "label": "kinetic energy"}], "answer": "d", "explanation": "Yes! The answer is \"kinetic energy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which of these gives off light and heat energy?", "choices": [{"id": "a", "label": "a rock"}, {"id": "b", "label": "the Sun"}, {"id": "c", "label": "a glass of water"}, {"id": "d", "label": "a wooden chair"}], "answer": "b", "explanation": "Yes! The answer is \"the Sun\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Plants store energy from sunlight in the form of:", "choices": [{"id": "a", "label": "water"}, {"id": "b", "label": "soil"}, {"id": "c", "label": "air"}, {"id": "d", "label": "food (sugar)"}], "answer": "d", "explanation": "Yes! The answer is \"food (sugar)\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Energy & Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$energy$tl$ and t.grade_level = 4);

-- science: Waves: Light & Sound
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Waves: Light & Sound", "body": "Sound is made by vibrations that travel as waves. We see things when light bounces off them and reaches our eyes."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Sound is made when objects do what?\n\nThe answer is \"vibrate\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  We see most objects because light does what off of them?\n\nThe answer is \"reflects (bounces)\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Sound travels as a kind of:\n\nThe answer is \"wave\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A louder sound is made by a vibration with a bigger:", "choices": [{"id": "a", "label": "color"}, {"id": "b", "label": "weight"}, {"id": "c", "label": "smell"}, {"id": "d", "label": "amplitude"}], "answer": "d", "explanation": "Yes! The answer is \"amplitude\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which travels faster?", "choices": [{"id": "a", "label": "sound"}, {"id": "b", "label": "they never move"}, {"id": "c", "label": "light"}, {"id": "d", "label": "neither moves"}], "answer": "c", "explanation": "Yes! The answer is \"light\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "You cannot see in a completely dark room because there is no:", "choices": [{"id": "a", "label": "sound"}, {"id": "b", "label": "air"}, {"id": "c", "label": "light"}, {"id": "d", "label": "water"}], "answer": "c", "explanation": "Yes! The answer is \"light\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Waves: Light & Sound! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$waves-light-sound$tl$ and t.grade_level = 4);

-- science: Plant Structures & Functions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Plant Structures & Functions", "body": "Plants have parts with special jobs: roots take in water, leaves make food from sunlight, stems carry water, and flowers make seeds."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which plant part takes in water from the soil?\n\nThe answer is \"roots\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which plant part makes food using sunlight?\n\nThe answer is \"leaves\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which part of a plant usually makes seeds?\n\nThe answer is \"flower\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What carries water from the roots up to the leaves?", "choices": [{"id": "a", "label": "the petals"}, {"id": "b", "label": "the seeds"}, {"id": "c", "label": "the stem"}, {"id": "d", "label": "the fruit"}], "answer": "c", "explanation": "Yes! The answer is \"the stem\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The process plants use to make food from sunlight is called:", "choices": [{"id": "a", "label": "digestion"}, {"id": "b", "label": "erosion"}, {"id": "c", "label": "photosynthesis"}, {"id": "d", "label": "evaporation"}], "answer": "c", "explanation": "Yes! The answer is \"photosynthesis\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Why are brightly colored flowers helpful to a plant?", "choices": [{"id": "a", "label": "they scare away the Sun"}, {"id": "b", "label": "they make the plant cold"}, {"id": "c", "label": "they attract pollinators like bees"}, {"id": "d", "label": "they stop water"}], "answer": "c", "explanation": "Yes! The answer is \"they attract pollinators like bees\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Plant Structures & Functions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
