  where s.slug = $tl$science$tl$ and t.slug = $tl$plant-structures$tl$ and t.grade_level = 4);

-- science: Animal Structures & Senses
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Animal Structures & Senses", "body": "Animals have body parts and senses that help them survive - to find food, sense danger, move, and stay warm."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which body part do most animals use to sense light?\n\nThe answer is \"eyes\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  An animal uses its ears mainly to:\n\nThe answer is \"hear sounds\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Sharp claws and teeth most help an animal to:\n\nThe answer is \"catch and eat food\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Thick fur or feathers most help an animal to:", "choices": [{"id": "a", "label": "run faster only"}, {"id": "b", "label": "stay warm"}, {"id": "c", "label": "see better"}, {"id": "d", "label": "smell food"}], "answer": "b", "explanation": "Yes! The answer is \"stay warm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which structure helps a fish move through water?", "choices": [{"id": "a", "label": "fins"}, {"id": "b", "label": "lungs"}, {"id": "c", "label": "wings"}, {"id": "d", "label": "hooves"}], "answer": "a", "explanation": "Yes! The answer is \"fins\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Animals use information from their senses to help them:", "choices": [{"id": "a", "label": "survive (find food, avoid danger)"}, {"id": "b", "label": "grow taller only"}, {"id": "c", "label": "change color of the sky"}, {"id": "d", "label": "stop breathing"}], "answer": "a", "explanation": "Yes! The answer is \"survive (find food, avoid danger)\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Animal Structures & Senses! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$animal-structures-senses$tl$ and t.grade_level = 4);

-- science: Earth's Features & Maps
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Earth's Features & Maps", "body": "Earth has oceans, mountains, rivers, valleys, and deserts. Maps use symbols and a key to show where these features are."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A very large area of salt water on Earth is called an:\n\nThe answer is \"ocean\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A tall landform that rises high above the land around it is a:\n\nThe answer is \"mountain\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Most of Earth's surface is covered by:\n\nThe answer is \"water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A map uses symbols and a key to show:", "choices": [{"id": "a", "label": "the future"}, {"id": "b", "label": "sounds"}, {"id": "c", "label": "places and features"}, {"id": "d", "label": "smells"}], "answer": "c", "explanation": "Yes! The answer is \"places and features\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A low area of land between mountains is called a:", "choices": [{"id": "a", "label": "valley"}, {"id": "b", "label": "peak"}, {"id": "c", "label": "plateau"}, {"id": "d", "label": "cliff"}], "answer": "a", "explanation": "Yes! The answer is \"valley\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Fresh water that flows across land toward the sea is a:", "choices": [{"id": "a", "label": "dune"}, {"id": "b", "label": "crater"}, {"id": "c", "label": "river"}, {"id": "d", "label": "glacier"}], "answer": "c", "explanation": "Yes! The answer is \"river\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Earth's Features & Maps! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$earths-features$tl$ and t.grade_level = 4);

-- science: Weathering & Erosion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Weathering & Erosion", "body": "Weathering breaks rock into smaller pieces. Erosion is when wind or water carries those pieces away, slowly changing the land."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Wind and water slowly breaking rock into smaller pieces is called:\n\nThe answer is \"weathering\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Moving water carrying away soil and sand is called:\n\nThe answer is \"erosion\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which can wear down a mountain over a very long time?\n\nThe answer is \"wind and water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Plant roots can break rocks apart as they:", "choices": [{"id": "a", "label": "shrink"}, {"id": "b", "label": "grow"}, {"id": "c", "label": "freeze the Sun"}, {"id": "d", "label": "reflect light"}], "answer": "b", "explanation": "Yes! The answer is \"grow\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When a river drops the sand and soil it was carrying, this is called:", "choices": [{"id": "a", "label": "weathering"}, {"id": "b", "label": "deposition"}, {"id": "c", "label": "vibration"}, {"id": "d", "label": "photosynthesis"}], "answer": "b", "explanation": "Yes! The answer is \"deposition\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which change happens very slowly, over many years?", "choices": [{"id": "a", "label": "a glass breaking"}, {"id": "b", "label": "a canyon being carved by a river"}, {"id": "c", "label": "a light turning on"}, {"id": "d", "label": "a door closing"}], "answer": "b", "explanation": "Yes! The answer is \"a canyon being carved by a river\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Weathering & Erosion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$weathering-erosion$tl$ and t.grade_level = 4);

-- science: Fossils & Rock Layers
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Fossils & Rock Layers", "body": "Fossils are preserved traces of ancient living things, usually found in sedimentary rock. Lower rock layers are usually older."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A fossil is the preserved remains or trace of a:\n\nThe answer is \"living thing from long ago\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Fossils are most often found in which kind of rock?\n\nThe answer is \"sedimentary rock\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  In undisturbed rock layers, the OLDEST layer is usually:\n\nThe answer is \"at the bottom\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Fossils can tell us about:", "choices": [{"id": "a", "label": "tomorrow's weather"}, {"id": "b", "label": "the price of food"}, {"id": "c", "label": "living things and environments of the past"}, {"id": "d", "label": "what someone is thinking"}], "answer": "c", "explanation": "Yes! The answer is \"living things and environments of the past\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A dinosaur footprint turned to stone is an example of a:", "choices": [{"id": "a", "label": "mineral crystal"}, {"id": "b", "label": "raindrop"}, {"id": "c", "label": "modern shoe"}, {"id": "d", "label": "trace fossil"}], "answer": "d", "explanation": "Yes! The answer is \"trace fossil\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Rock layers form over time as ____ piles up and hardens.", "choices": [{"id": "a", "label": "sunlight"}, {"id": "b", "label": "sound"}, {"id": "c", "label": "wind only"}, {"id": "d", "label": "sediment"}], "answer": "d", "explanation": "Yes! The answer is \"sediment\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Fossils & Rock Layers! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$fossils-rock-layers$tl$ and t.grade_level = 4);

-- science: Natural Resources & Conservation
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Natural Resources & Conservation", "body": "Natural resources come from Earth. Some are renewable (sunlight, wind) and some are not (coal, oil). Conserving them protects the planet."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which is a natural resource that comes from the Earth?\n\nThe answer is \"water\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which energy resource is renewable (it won't run out)?\n\nThe answer is \"sunlight\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Coal and oil are called fossil fuels and are:\n\nThe answer is \"nonrenewable\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Recycling helps us:", "choices": [{"id": "a", "label": "use fewer new resources"}, {"id": "b", "label": "use up more oil"}, {"id": "c", "label": "make more trash"}, {"id": "d", "label": "waste water"}], "answer": "a", "explanation": "Yes! The answer is \"use fewer new resources\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is a way to conserve water?", "choices": [{"id": "a", "label": "leave the hose running"}, {"id": "b", "label": "turn off the tap while brushing teeth"}, {"id": "c", "label": "take very long showers"}, {"id": "d", "label": "pour water on the road"}], "answer": "b", "explanation": "Yes! The answer is \"turn off the tap while brushing teeth\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Wind can be used to make electricity using a:", "choices": [{"id": "a", "label": "wind turbine"}, {"id": "b", "label": "coal mine"}, {"id": "c", "label": "oil well"}, {"id": "d", "label": "candle"}], "answer": "a", "explanation": "Yes! The answer is \"wind turbine\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Natural Resources & Conservation! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$natural-resources$tl$ and t.grade_level = 4);

-- science: Electricity & Magnetism
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Electricity & Magnetism", "body": "Electricity flows through conductors like metal in a complete circuit. Magnets attract iron and have poles that attract or repel."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Electricity flows easily through which material?\n\nThe answer is \"metal wire\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A material that does NOT let electricity flow easily is called an:\n\nThe answer is \"insulator\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A magnet attracts objects made of:\n\nThe answer is \"iron\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Two magnets pushing apart are showing that like poles:", "choices": [{"id": "a", "label": "attract"}, {"id": "b", "label": "melt"}, {"id": "c", "label": "disappear"}, {"id": "d", "label": "repel"}], "answer": "d", "explanation": "Yes! The answer is \"repel\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A complete path that lets electricity flow is called a:", "choices": [{"id": "a", "label": "magnet"}, {"id": "b", "label": "fossil"}, {"id": "c", "label": "circuit"}, {"id": "d", "label": "wave"}], "answer": "c", "explanation": "Yes! The answer is \"circuit\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is a conductor of electricity?", "choices": [{"id": "a", "label": "wood"}, {"id": "b", "label": "rubber"}, {"id": "c", "label": "copper"}, {"id": "d", "label": "cloth"}], "answer": "c", "explanation": "Yes! The answer is \"copper\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Electricity & Magnetism! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$electricity-magnetism$tl$ and t.grade_level = 4);

-- science: The Water Cycle & Weather
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: The Water Cycle & Weather", "body": "The Sun drives the water cycle: water evaporates, condenses into clouds, and falls as precipitation. Weather is the day-to-day state of the air."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  When the Sun heats water and it turns into vapor, this is:\n\nThe answer is \"evaporation\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Water vapor cooling and forming clouds is called:\n\nThe answer is \"condensation\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Rain, snow, and hail are all forms of:\n\nThe answer is \"precipitation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Clouds are made of tiny drops of:", "choices": [{"id": "a", "label": "water"}, {"id": "b", "label": "smoke"}, {"id": "c", "label": "dust only"}, {"id": "d", "label": "sand"}], "answer": "a", "explanation": "Yes! The answer is \"water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The day-to-day condition of the air (sunny, rainy) is called:", "choices": [{"id": "a", "label": "climate forever"}, {"id": "b", "label": "weather"}, {"id": "c", "label": "gravity"}, {"id": "d", "label": "erosion"}], "answer": "b", "explanation": "Yes! The answer is \"weather\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Most of the water that evaporates into the sky comes from the:", "choices": [{"id": "a", "label": "oceans"}, {"id": "b", "label": "deserts"}, {"id": "c", "label": "rocks"}, {"id": "d", "label": "fires"}], "answer": "a", "explanation": "Yes! The answer is \"oceans\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about The Water Cycle & Weather! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$water-cycle-weather$tl$ and t.grade_level = 4);

-- reading: Finding the Main Idea
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Finding the Main Idea", "body": "The main idea is what a passage is mostly about. Ask yourself: what is the one big point the author wants me to understand?"}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Bees are very important. They move pollen from flower to flower, which helps plants make seeds and fruit. Without bees, many foods would be hard to grow.\" What is the main idea?\n\nThe answer is \"Bees are important because they help plants grow.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Maria practiced piano every day after school. At first the songs were hard, but slowly she got better. By spring, she could play her favorite song perfectly.\" What is the main idea?\n\nThe answer is \"Practice helped Maria improve at piano.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Penguins live where it is very cold. Their thick feathers and a layer of fat keep them warm. They huddle together to share heat.\" The passage is mostly about how penguins:\n\nThe answer is \"stay warm in cold places\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Recycling helps the Earth. It saves trees, uses less energy, and keeps trash out of landfills.\" What is the main idea?", "choices": [{"id": "a", "label": "Recycling is good for the Earth."}, {"id": "b", "label": "Trees are tall."}, {"id": "c", "label": "Trash smells bad."}, {"id": "d", "label": "Landfills are far away."}], "answer": "a", "explanation": "Yes! The answer is \"Recycling is good for the Earth.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The school garden grew many vegetables. Students planted seeds, watered them, and pulled weeds. In the fall, they picked tomatoes and carrots.\" What is the main idea?", "choices": [{"id": "a", "label": "Students grew vegetables in the school garden."}, {"id": "b", "label": "Carrots are orange."}, {"id": "c", "label": "School starts early."}, {"id": "d", "label": "Weeds are tall."}], "answer": "a", "explanation": "Yes! The answer is \"Students grew vegetables in the school garden.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Sea turtles travel thousands of miles in the ocean. They return to the same beach where they were born to lay their eggs.\" The main idea is that sea turtles:", "choices": [{"id": "a", "label": "travel far and return to their home beach"}, {"id": "b", "label": "eat jellyfish"}, {"id": "c", "label": "are very old"}, {"id": "d", "label": "swim slowly"}], "answer": "a", "explanation": "Yes! The answer is \"travel far and return to their home beach\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Finding the Main Idea! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$main-idea$tl$ and t.grade_level = 4);

-- reading: Supporting Details
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Supporting Details", "body": "Supporting details are the facts and examples that tell more about the main idea. They answer who, what, where, when, why, and how."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Dogs make great pets. They are loyal, they can be trained, and they love to play.\" Which is a detail that supports the main idea?\n\nThe answer is \"They can be trained.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Our trip to the zoo was fun. We saw lions, fed the goats, and watched the monkeys swing.\" Which detail tells something they did at the zoo?\n\nThe answer is \"We fed the goats.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Winter can be dangerous. Roads get icy, the cold can hurt your skin, and storms can knock out power.\" Which detail supports that winter is dangerous?\n\nThe answer is \"Roads get icy.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Plants need care to grow. They need water, sunlight, and good soil.\" Which is a supporting detail?", "choices": [{"id": "a", "label": "Rocks are hard."}, {"id": "b", "label": "The sky is blue."}, {"id": "c", "label": "They need sunlight."}, {"id": "d", "label": "Dogs bark."}], "answer": "c", "explanation": "Yes! The answer is \"They need sunlight.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The festival had lots to enjoy. There was music, tasty food, and games for kids.\" Which detail supports that there was a lot to enjoy?", "choices": [{"id": "a", "label": "It was Tuesday."}, {"id": "b", "label": "The town is small."}, {"id": "c", "label": "Cars were parked."}, {"id": "d", "label": "There were games for kids."}], "answer": "d", "explanation": "Yes! The answer is \"There were games for kids.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Exercise keeps you healthy. It makes your heart strong, builds muscles, and lifts your mood.\" A supporting detail is that exercise:", "choices": [{"id": "a", "label": "makes your heart strong"}, {"id": "b", "label": "takes time"}, {"id": "c", "label": "is on TV"}, {"id": "d", "label": "needs shoes"}], "answer": "a", "explanation": "Yes! The answer is \"makes your heart strong\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Supporting Details! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$supporting-details$tl$ and t.grade_level = 4);

-- reading: Sequence of Events
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Sequence of Events", "body": "Sequence is the order things happen. Signal words like first, next, then, and last help you keep track of the order."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"First Sam woke up. Next he ate breakfast. Then he walked to school.\" What did Sam do FIRST?\n\nThe answer is \"He woke up.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"To make a sandwich, first get the bread. Then add the filling. Last, cut it in half.\" What do you do LAST?\n\nThe answer is \"Cut it in half.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The seed sprouted. Then it grew leaves. Finally it bloomed into a flower.\" What happened SECOND?\n\nThe answer is \"It grew leaves.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Mia drew a picture, then colored it, and finally hung it on the wall.\" What did Mia do right AFTER drawing?", "choices": [{"id": "a", "label": "She hung it up."}, {"id": "b", "label": "She erased it."}, {"id": "c", "label": "She slept."}, {"id": "d", "label": "She colored it."}], "answer": "d", "explanation": "Yes! The answer is \"She colored it.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"First the clouds gathered. Next it began to rain. Then a rainbow appeared.\" What came BEFORE the rain?", "choices": [{"id": "a", "label": "The rainbow."}, {"id": "b", "label": "The clouds gathered."}, {"id": "c", "label": "The sun set."}, {"id": "d", "label": "The snow fell."}], "answer": "b", "explanation": "Yes! The answer is \"The clouds gathered.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Leo packed his bag, ate lunch, and then left for the trip.\" What did Leo do BEFORE leaving?", "choices": [{"id": "a", "label": "He came home."}, {"id": "b", "label": "He unpacked."}, {"id": "c", "label": "He ate lunch."}, {"id": "d", "label": "He slept."}], "answer": "c", "explanation": "Yes! The answer is \"He ate lunch.\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Sequence of Events! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$sequence$tl$ and t.grade_level = 4);

-- reading: Cause & Effect
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Cause & Effect", "body": "A cause is why something happens; the effect is what happens. Words like because and so often connect them."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Because it rained all day, the soccer game was canceled.\" What was the CAUSE?\n\nThe answer is \"It rained all day.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Tom forgot to water his plant, so it wilted.\" What was the EFFECT?\n\nThe answer is \"The plant wilted.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The ice melted because the day was very hot.\" Why did the ice melt?\n\nThe answer is \"The day was very hot.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She studied hard, so she passed the test.\" What caused her to pass?", "choices": [{"id": "a", "label": "The test was easy."}, {"id": "b", "label": "She was late."}, {"id": "c", "label": "She slept in class."}, {"id": "d", "label": "She studied hard."}], "answer": "d", "explanation": "Yes! The answer is \"She studied hard.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The dog barked loudly, so the baby woke up.\" What was the effect of the barking?", "choices": [{"id": "a", "label": "The dog slept."}, {"id": "b", "label": "The baby ate."}, {"id": "c", "label": "The dog ran."}, {"id": "d", "label": "The baby woke up."}], "answer": "d", "explanation": "Yes! The answer is \"The baby woke up.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Because the road was icy, the cars drove slowly.\" Why did the cars drive slowly?", "choices": [{"id": "a", "label": "The cars were red."}, {"id": "b", "label": "It was sunny."}, {"id": "c", "label": "The road was icy."}, {"id": "d", "label": "The road was new."}], "answer": "c", "explanation": "Yes! The answer is \"The road was icy.\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Cause & Effect! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$cause-and-effect$tl$ and t.grade_level = 4);

-- reading: Vocabulary in Context
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Vocabulary in Context", "body": "When you meet a new word, use the other words around it - the context - as clues to figure out what it means."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The path was so narrow that only one person could pass at a time.\" What does \"narrow\" mean?\n\nThe answer is \"not wide\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The soup was scalding, so she waited for it to cool.\" What does \"scalding\" mean?\n\nThe answer is \"very hot\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"He was exhausted after the long run and fell asleep right away.\" What does \"exhausted\" mean?\n\nThe answer is \"very tired\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The ancient ruins were thousands of years old.\" What does \"ancient\" mean?", "choices": [{"id": "a", "label": "brand new"}, {"id": "b", "label": "very old"}, {"id": "c", "label": "colorful"}, {"id": "d", "label": "tiny"}], "answer": "b", "explanation": "Yes! The answer is \"very old\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The puppy was timid and hid behind the couch when strangers came.\" What does \"timid\" mean?", "choices": [{"id": "a", "label": "loud"}, {"id": "b", "label": "huge"}, {"id": "c", "label": "fast"}, {"id": "d", "label": "shy or fearful"}], "answer": "d", "explanation": "Yes! The answer is \"shy or fearful\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She spoke in a faint whisper that was hard to hear.\" What does \"faint\" mean here?", "choices": [{"id": "a", "label": "very loud"}, {"id": "b", "label": "weak or soft"}, {"id": "c", "label": "bright"}, {"id": "d", "label": "sweet"}], "answer": "b", "explanation": "Yes! The answer is \"weak or soft\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Vocabulary in Context! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$context-clues$tl$ and t.grade_level = 4);

-- reading: Making Inferences
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Making Inferences", "body": "An inference is a smart guess based on clues in the text plus what you already know. The text hints, and you figure out the rest."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Maya grabbed her umbrella and rain boots before heading out.\" What can you infer?\n\nThe answer is \"It is probably raining or going to rain.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Jake's stomach growled and he kept looking at the clock near lunchtime.\" What can you infer?\n\nThe answer is \"Jake is hungry.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The streets were empty and all the shops had their lights off.\" What can you infer?\n\nThe answer is \"It is very early or very late.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Tia smiled wide and hugged the trophy to her chest.\" What can you infer?", "choices": [{"id": "a", "label": "Tia is sad."}, {"id": "b", "label": "Tia is bored."}, {"id": "c", "label": "Tia is happy that she won."}, {"id": "d", "label": "Tia is afraid."}], "answer": "c", "explanation": "Yes! The answer is \"Tia is happy that she won.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The leaves were turning red and orange, and kids wore jackets to school.\" What season is it?", "choices": [{"id": "a", "label": "Fall (autumn)"}, {"id": "b", "label": "Summer"}, {"id": "c", "label": "A hot day"}, {"id": "d", "label": "Spring planting"}], "answer": "a", "explanation": "Yes! The answer is \"Fall (autumn)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Ben tiptoed and whispered as he passed the baby's room.\" What can you infer?", "choices": [{"id": "a", "label": "The baby is playing."}, {"id": "b", "label": "Ben is loud."}, {"id": "c", "label": "The baby is sleeping."}, {"id": "d", "label": "It is a party."}], "answer": "c", "explanation": "Yes! The answer is \"The baby is sleeping.\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Making Inferences! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$making-inferences$tl$ and t.grade_level = 4);

-- reading: Author's Purpose
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Author's Purpose", "body": "Authors write to persuade, inform, instruct, or entertain. Ask why the author wrote this to find the purpose."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An author writes \"10 Steps to Build a Birdhouse.\" The author's purpose is mainly to:\n\nThe answer is \"instruct (teach how to do something)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A funny story about a talking dog is written mainly to:\n\nThe answer is \"entertain\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An article titled \"Why Our Town Needs a New Park\" is written mainly to:\n\nThe answer is \"persuade\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A page in a science book explaining how rain forms is written mainly to:", "choices": [{"id": "a", "label": "scare the reader"}, {"id": "b", "label": "sell toys"}, {"id": "c", "label": "make you laugh"}, {"id": "d", "label": "inform"}], "answer": "d", "explanation": "Yes! The answer is \"inform\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A poster that says \"Eat more vegetables for a healthy body!\" is meant to:", "choices": [{"id": "a", "label": "report sports scores"}, {"id": "b", "label": "persuade"}, {"id": "c", "label": "tell a mystery"}, {"id": "d", "label": "teach math"}], "answer": "b", "explanation": "Yes! The answer is \"persuade\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A cookbook recipe is written mainly to:", "choices": [{"id": "a", "label": "entertain"}, {"id": "b", "label": "persuade"}, {"id": "c", "label": "instruct"}, {"id": "d", "label": "tell news"}], "answer": "c", "explanation": "Yes! The answer is \"instruct\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Author's Purpose! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$authors-purpose$tl$ and t.grade_level = 4);

-- reading: Compare & Contrast
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Compare & Contrast", "body": "Comparing tells how things are alike; contrasting tells how they are different. Words like both signal alike; but and unlike signal different."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Cats and dogs are both popular pets, but cats are usually quieter and dogs like to play fetch.\" One way they are the SAME is:\n\nThe answer is \"both are popular pets\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"A bicycle has two wheels, while a car has four.\" This sentence shows a:\n\nThe answer is \"difference\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Both apples and oranges are fruits that grow on trees.\" The word that signals they are alike is:\n\nThe answer is \"both\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Summer is hot, but winter is cold.\" This compares the two seasons by their:", "choices": [{"id": "a", "label": "color"}, {"id": "b", "label": "size"}, {"id": "c", "label": "name"}, {"id": "d", "label": "temperature"}], "answer": "d", "explanation": "Yes! The answer is \"temperature\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Unlike a frog, a fish cannot live out of water.\" The word \"unlike\" signals a:", "choices": [{"id": "a", "label": "similarity"}, {"id": "b", "label": "difference"}, {"id": "c", "label": "sequence"}, {"id": "d", "label": "cause"}], "answer": "b", "explanation": "Yes! The answer is \"difference\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"A pencil and a pen are both used for writing, but a pencil can be erased.\" How are they DIFFERENT?", "choices": [{"id": "a", "label": "a pencil can be erased"}, {"id": "b", "label": "both write"}, {"id": "c", "label": "both are tools"}, {"id": "d", "label": "both are long"}], "answer": "a", "explanation": "Yes! The answer is \"a pencil can be erased\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Compare & Contrast! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$compare-and-contrast$tl$ and t.grade_level = 4);

-- reading: Fact vs. Opinion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Fact vs. Opinion", "body": "A fact can be proven true. An opinion tells what someone feels or believes and can't be proven. Words like best or favorite often signal opinions."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which sentence is a FACT?\n\nThe answer is \"Water freezes at 0 degrees Celsius.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which sentence is an OPINION?\n\nThe answer is \"Recess is the most fun part of the day.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which is a FACT?\n\nThe answer is \"A triangle has three sides.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is an OPINION?", "choices": [{"id": "a", "label": "Chocolate ice cream is the best flavor."}, {"id": "b", "label": "Ice melts when heated."}, {"id": "c", "label": "There are 12 months in a year."}, {"id": "d", "label": "Plants need sunlight."}], "answer": "a", "explanation": "Yes! The answer is \"Chocolate ice cream is the best flavor.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Our school has 400 students.\" This statement is a:", "choices": [{"id": "a", "label": "fact"}, {"id": "b", "label": "opinion"}, {"id": "c", "label": "question"}, {"id": "d", "label": "story"}], "answer": "a", "explanation": "Yes! The answer is \"fact\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Reading is more fun than watching TV.\" This statement is an:", "choices": [{"id": "a", "label": "fact"}, {"id": "b", "label": "math problem"}, {"id": "c", "label": "opinion"}, {"id": "d", "label": "rule"}], "answer": "c", "explanation": "Yes! The answer is \"opinion\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Fact vs. Opinion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$fact-and-opinion$tl$ and t.grade_level = 4);

-- reading: Synonyms & Antonyms
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Synonyms & Antonyms", "body": "Synonyms are words that mean almost the same thing. Antonyms are words that mean the opposite."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is a SYNONYM (same meaning) for \"happy\"?\n\nThe answer is \"glad\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is an ANTONYM (opposite) of \"big\"?\n\nThe answer is \"small\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word means almost the same as \"fast\"?\n\nThe answer is \"quick\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is the opposite of \"hot\"?", "choices": [{"id": "a", "label": "warm"}, {"id": "b", "label": "cold"}, {"id": "c", "label": "boiling"}, {"id": "d", "label": "sunny"}], "answer": "b", "explanation": "Yes! The answer is \"cold\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A synonym for \"begin\" is:", "choices": [{"id": "a", "label": "start"}, {"id": "b", "label": "stop"}, {"id": "c", "label": "end"}, {"id": "d", "label": "finish"}], "answer": "a", "explanation": "Yes! The answer is \"start\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An antonym for \"empty\" is:", "choices": [{"id": "a", "label": "bare"}, {"id": "b", "label": "full"}, {"id": "c", "label": "hollow"}, {"id": "d", "label": "vacant"}], "answer": "b", "explanation": "Yes! The answer is \"full\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Synonyms & Antonyms! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$synonyms-and-antonyms$tl$ and t.grade_level = 4);

-- writing: Nouns
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Nouns", "body": "A noun names a person, place, thing, or idea. Common nouns are general (city); proper nouns name a specific one (Paris)."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"pencil\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"island\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"puppy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "ancient"}, {"id": "b", "label": "garden"}, {"id": "c", "label": "curious"}, {"id": "d", "label": "build"}], "answer": "b", "explanation": "Yes! The answer is \"garden\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "slippery"}, {"id": "b", "label": "frozen"}, {"id": "c", "label": "sister"}, {"id": "d", "label": "brave"}], "answer": "c", "explanation": "Yes! The answer is \"sister\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "whisper"}, {"id": "b", "label": "frozen"}, {"id": "c", "label": "gallop"}, {"id": "d", "label": "mountain"}], "answer": "d", "explanation": "Yes! The answer is \"mountain\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Nouns! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$writing$tl$ and t.slug = $tl$nouns$tl$ and t.grade_level = 4);

-- writing: Action Verbs
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Action Verbs", "body": "A verb shows action or a state of being. Action verbs tell what the subject does, like run, jump, or think."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is an action verb (something you can do)?\n\nThe answer is \"wander\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is an action verb (something you can do)?\n\nThe answer is \"stretch\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is an action verb (something you can do)?\n\nThe answer is \"whisper\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "bounce"}, {"id": "b", "label": "island"}, {"id": "c", "label": "forest"}, {"id": "d", "label": "farmer"}], "answer": "a", "explanation": "Yes! The answer is \"bounce\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "swim"}, {"id": "b", "label": "sister"}, {"id": "c", "label": "gentle"}, {"id": "d", "label": "doctor"}], "answer": "a", "explanation": "Yes! The answer is \"swim\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "garden"}, {"id": "b", "label": "library"}, {"id": "c", "label": "paint"}, {"id": "d", "label": "ancient"}], "answer": "c", "explanation": "Yes! The answer is \"paint\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Action Verbs! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$writing$tl$ and t.slug = $tl$action-verbs$tl$ and t.grade_level = 4);

-- writing: Adjectives
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Adjectives", "body": "An adjective describes a noun - telling what kind, how many, or which one, like shiny, three, or that."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is an adjective (it describes a noun)?\n\nThe answer is \"fluffy\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is an adjective (it describes a noun)?\n\nThe answer is \"tiny\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is an adjective (it describes a noun)?\n\nThe answer is \"golden\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an adjective (it describes a noun)?", "choices": [{"id": "a", "label": "sister"}, {"id": "b", "label": "pencil"}, {"id": "c", "label": "brave"}, {"id": "d", "label": "build"}], "answer": "c", "explanation": "Yes! The answer is \"brave\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an adjective (it describes a noun)?", "choices": [{"id": "a", "label": "kitchen"}, {"id": "b", "label": "garden"}, {"id": "c", "label": "cheerful"}, {"id": "d", "label": "discover"}], "answer": "c", "explanation": "Yes! The answer is \"cheerful\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an adjective (it describes a noun)?", "choices": [{"id": "a", "label": "march"}, {"id": "b", "label": "jump"}, {"id": "c", "label": "forest"}, {"id": "d", "label": "narrow"}], "answer": "d", "explanation": "Yes! The answer is \"narrow\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Adjectives! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
